import React, { useState, useEffect } from "react";

const API = "https://prasa-backend-1.onrender.com";

export default function AddTicket({ employee }) {
  const [form, setForm] = useState({
    ticket_date: "",
    purpose: "",
    assigned_to: "",
    amount: "",
  });

  const [ticketList, setTicketList] = useState([]);
  const [filterMonth, setFilterMonth] = useState("");

  const loadTickets = async () => {
    try {
      const res = await fetch(`${API}/ticket/${employee.empld}`);
      const json = await res.json();
      const list = Array.isArray(json.data) ? json.data : [];
      setTicketList(list);
    } catch (err) {
      console.error("Ticket Load Error:", err);
    }
  };

  useEffect(() => {
    if (employee?.empld) loadTickets();
  }, [employee]);

  const saveTicket = async () => {
    if (!form.ticket_date || !form.amount) {
      alert("Please fill required fields!");
      return;
    }

    const res = await fetch(`${API}/ticket/add`, {
      method: "POST",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify({ ...form, empld: employee.empld }),
    });

    const json = await res.json();
    if (json.success) {
      alert("Ticket expense added!");
      setForm({
        ticket_date: "",
        purpose: "",
        assigned_to: "",
        amount: "",
      });
      loadTickets();
    }
  };

  const deleteTicket = async (id) => {
    if (!window.confirm("Delete this?")) return;

    await fetch(`${API}/ticket/delete/${id}`, { method: "DELETE" });
    loadTickets();
  };

  const filteredList = ticketList.filter((t) =>
    filterMonth ? t.ticket_date.startsWith(filterMonth) : true
  );

  return (
    <div className="page-container">
      <h2>Ticket Expense</h2>

      <div className="form-card">
        <input
          type="date"
          value={form.ticket_date}
          onChange={(e) => setForm({ ...form, ticket_date: e.target.value })}
        />
        <input
          type="text"
          placeholder="Purpose"
          value={form.purpose}
          onChange={(e) => setForm({ ...form, purpose: e.target.value })}
        />
        <input
          type="text"
          placeholder="Assigned To"
          value={form.assigned_to}
          onChange={(e) => setForm({ ...form, assigned_to: e.target.value })}
        />
        <input
          type="number"
          placeholder="Amount"
          value={form.amount}
          onChange={(e) => setForm({ ...form, amount: e.target.value })}
        />

        <button className="save-btn" onClick={saveTicket}>
          Save Ticket Expense
        </button>
      </div>

      {/* FILTER */}
      <div className="filter-section">
        <input
          type="month"
          value={filterMonth}
          onChange={(e) => setFilterMonth(e.target.value)}
        />
      </div>

      {/* TABLE */}
      <div className="table-card">
        <h3>Ticket History</h3>

        {filteredList.length === 0 ? (
          <p>No ticket records</p>
        ) : (
          <table>
            <thead>
              <tr>
                <th>Date</th>
                <th>Purpose</th>
                <th>Assigned</th>
                <th>Amount</th>
                <th>Status</th>
                <th>Delete</th>
              </tr>
            </thead>

            <tbody>
              {filteredList.map((t) => (
                <tr key={t.id}>
                  <td>{t.ticket_date}</td>
                  <td>{t.purpose}</td>
                  <td>{t.assigned_to}</td>
                  <td>₹{t.amount}</td>
                  <td>
                    <span
                      className={
                        t.status === "Approved" ? "status-approved" : "status-pending"
                      }
                    >
                      {t.status}
                    </span>
                  </td>
                  <td>
                    <button className="delete-btn" onClick={() => deleteTicket(t.id)}>
                      ❌
                    </button>
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        )}
      </div>
    </div>
  );
}
